def api_local_iso(value: Optional[datetime]) -> Optional[str]:
    if not value:
        return None
    if value.tzinfo is None:
        return value.replace(tzinfo=LOCAL_TZ).isoformat()
    return value.astimezone(LOCAL_TZ).isoformat()


def api_import_status_row(row: Dict[str, Any]) -> Dict[str, Any]:
    payload = dict(row)
    for key in ("last_success_at", "last_run_at", "last_failed_at", "next_expected_at"):
        payload[key] = api_local_iso(payload.get(key))
    return payload


def api_import_status_rows(rows: list[Dict[str, Any]]) -> list[Dict[str, Any]]:
    return [api_import_status_row(row) for row in rows]


def api_bool_state(value: Any) -> Optional[bool]:
    if value is None:
        return None
    return bool(value)


def api_revenue_day(row: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "day": row["day"].isoformat(),
        "dayLabel": row["day_label"],
        "weekday": row["weekday"],
        "sol": row["sol"],
        "solCount": row["sol_count"],
        "parking": row["parking"],
        "parkingCount": row["parking_count"],
        "total": row["total"],
        "isToday": row["is_today"],
        "isWeekend": row["is_weekend"],
    }


async def build_revenue_month_context(month: Optional[str] = None) -> Dict[str, Any]:
    today = local_now_naive().date()
    month_start = normalize_month(month, today)
    next_month = add_months(month_start, 1)
    previous_month = add_months(month_start, -1)
    days_in_month = (next_month - month_start).days
    async with async_session() as session:
        sol_rows = (
            await session.execute(
                select(
                    Sun2TanningSession.stat_date.label("day"),
                    func.count(Sun2TanningSession.id).label("count"),
                    func.coalesce(func.sum(Sun2TanningSession.paid_amount_kr), 0).label("amount"),
                )
                .where(Sun2TanningSession.stat_date >= month_start)
                .where(Sun2TanningSession.stat_date < next_month)
                .group_by(Sun2TanningSession.stat_date)
            )
        ).mappings().all()
        parking_day = cast(ParkingSession.start_time, Date)
        parking_rows = (
            await session.execute(
                select(
                    parking_day.label("day"),
                    func.count(ParkingSession.id).label("count"),
                    func.coalesce(func.sum(ParkingSession.fee_inc_vat), 0).label("amount"),
                )
                .where(ParkingSession.start_time >= datetime.combine(month_start, time.min))
                .where(ParkingSession.start_time < datetime.combine(next_month, time.min))
                .group_by(parking_day)
            )
        ).mappings().all()

    sol_by_day = {row["day"]: float_or_zero(row["amount"]) for row in sol_rows}
    sol_count_by_day = {row["day"]: int_or_zero(row["count"]) for row in sol_rows}
    parking_by_day = {row["day"]: float_or_zero(row["amount"]) for row in parking_rows}
    parking_count_by_day = {row["day"]: int_or_zero(row["count"]) for row in parking_rows}
    rows = []
    for offset in range(days_in_month):
        day = month_start + timedelta(days=offset)
        sol_amount = sol_by_day.get(day, 0.0)
        parking_amount = parking_by_day.get(day, 0.0)
        rows.append(
            {
                "day": day,
                "day_label": day.strftime("%d.%m"),
                "weekday": ["Man", "Tir", "Ons", "Tor", "Fre", "Lor", "Son"][day.weekday()],
                "sol": sol_amount,
                "sol_count": sol_count_by_day.get(day, 0),
                "parking": parking_amount,
                "parking_count": parking_count_by_day.get(day, 0),
                "total": sol_amount + parking_amount,
                "is_today": day == today,
                "is_weekend": day.weekday() >= 5,
            }
        )
    max_total = max([row["total"] for row in rows] + [1.0])
    for row in rows:
        row["sol_pct"] = 0.0 if row["sol"] <= 0 else max(4.0, row["sol"] / max_total * 100)
        row["parking_pct"] = 0.0 if row["parking"] <= 0 else max(4.0, row["parking"] / max_total * 100)
        if row["sol_pct"] + row["parking_pct"] > 100:
            scale = 100.0 / (row["sol_pct"] + row["parking_pct"])
            row["sol_pct"] *= scale
            row["parking_pct"] *= scale
    total_sol = sum(row["sol"] for row in rows)
    total_parking = sum(row["parking"] for row in rows)
    if month_start <= today < next_month:
        average_day_count = (today - month_start).days + 1
    elif month_start < today.replace(day=1):
        average_day_count = days_in_month
    else:
        average_day_count = 0
    average_per_day = (total_sol + total_parking) / average_day_count if average_day_count else 0.0
    top_day = max(rows, key=lambda row: row["total"], default=None)
    today_row = next((row for row in rows if row["day"] == today), None)
    return {
        "rows": rows,
        "summary": {
            "label": month_label(month_start),
            "month": month_start.strftime("%Y-%m"),
            "previous_month": previous_month.strftime("%Y-%m"),
            "next_month": next_month.strftime("%Y-%m"),
            "current_month": today.replace(day=1).strftime("%Y-%m"),
            "total": total_sol + total_parking,
            "sol": total_sol,
            "parking": total_parking,
            "sol_count": sum(row["sol_count"] for row in rows),
            "parking_count": sum(row["parking_count"] for row in rows),
            "average_day_count": average_day_count,
            "average_per_day": average_per_day,
            "max_total": max_total,
            "top_day": top_day,
            "today_row": today_row,
        },
    }


@app.get("/api/status/comparison")
async def api_v2_status_comparison(
    period: str = Query("today"),
    compare: str = Query("previous"),
    anchor: Optional[str] = Query(None),
):
    now_dt = local_now_naive()
    today = now_dt.date()
    anchor_day = parse_anchor_day(anchor, today)
    async with async_session() as session:
        import_rows = await import_status_rows(session)
        windows = status_comparison_windows(import_rows, now_dt, anchor_day)
        period_config = windows.get(period)
        if not period_config:
            raise HTTPException(status_code=404, detail="Ukjent statusperiode")
        comparison_config = next(
            (item for item in period_config["comparisons"] if item["key"] == compare),
            None,
        )
        if not comparison_config:
            raise HTTPException(status_code=404, detail="Ukjent sammenligning")
        reference_configs = [
            item
            for item in period_config["comparisons"]
            if item["key"] == "same-weekday-last-week" and item["key"] != comparison_config["key"]
        ]

        current_config = period_config["current"]
        full_day_chart = period == "today"

        def chart_start(config: Dict[str, Any]) -> datetime:
            if full_day_chart:
                return config["start"] + timedelta(hours=6)
            return config["start"]

        def chart_end(config: Dict[str, Any], source_key: str) -> datetime:
            if not full_day_chart:
                return config[source_key]
            window_start = chart_start(config)
            window_end = config["start"] + timedelta(days=1)
            if config is not current_config:
                return window_end
            return max(window_start, min(config[source_key], window_end))

        current_chart_start = chart_start(current_config)
        comparison_chart_start = chart_start(comparison_config)
        current_sun_chart_end = chart_end(current_config, "sunEnd")
        current_parking_chart_end = chart_end(current_config, "parkingEnd")
        comparison_sun_chart_end = chart_end(comparison_config, "sunEnd")
        comparison_parking_chart_end = chart_end(comparison_config, "parkingEnd")
        axis_candidates = [
            3600.0,
            (current_sun_chart_end - current_chart_start).total_seconds(),
            (current_parking_chart_end - current_chart_start).total_seconds(),
            (comparison_sun_chart_end - comparison_chart_start).total_seconds(),
            (comparison_parking_chart_end - comparison_chart_start).total_seconds(),
        ]
        for reference_config in reference_configs:
            reference_chart_start = chart_start(reference_config)
            reference_sun_chart_end = chart_end(reference_config, "sunEnd")
            reference_parking_chart_end = chart_end(reference_config, "parkingEnd")
            axis_candidates.extend(
                [
                    (reference_sun_chart_end - reference_chart_start).total_seconds(),
                    (reference_parking_chart_end - reference_chart_start).total_seconds(),
                ]
            )
        axis_seconds = max(axis_candidates)

        current_sun = await sun2_datetime_snapshot(session, current_config["start"], current_config["sunEnd"])
        current_parking = await parking_datetime_snapshot(session, current_config["start"], current_config["parkingEnd"])
        comparison_sun = await sun2_datetime_snapshot(session, comparison_config["start"], comparison_config["sunEnd"])
        comparison_parking = await parking_datetime_snapshot(
            session,
            comparison_config["start"],
            comparison_config["parkingEnd"],
        )

        lanes = [
            await status_timeline_lane(
                session,
                "current",
                "Soling",
                current_config["label"],
                "sun",
                current_chart_start,
                current_sun_chart_end,
                axis_seconds,
            ),
            await status_timeline_lane(
                session,
                "current",
                "Parkering",
                current_config["label"],
                "parking",
                current_chart_start,
                current_parking_chart_end,
                axis_seconds,
            ),
            await status_timeline_lane(
                session,
                "comparison",
                "Soling",
                comparison_config["label"],
                "sun",
                comparison_chart_start,
                comparison_sun_chart_end,
                axis_seconds,
            ),
            await status_timeline_lane(
                session,
                "comparison",
                "Parkering",
                comparison_config["label"],
                "parking",
                comparison_chart_start,
                comparison_parking_chart_end,
                axis_seconds,
            ),
        ]
        reference_results = []
        for reference_config in reference_configs:
            reference_chart_start = chart_start(reference_config)
            reference_sun_chart_end = chart_end(reference_config, "sunEnd")
            reference_parking_chart_end = chart_end(reference_config, "parkingEnd")
            reference_sun = await sun2_datetime_snapshot(session, reference_config["start"], reference_config["sunEnd"])
            reference_parking = await parking_datetime_snapshot(
                session,
                reference_config["start"],
                reference_config["parkingEnd"],
            )
            reference_lanes = [
                await status_timeline_lane(
                    session,
                    "reference",
                    "Soling",
                    reference_config["label"],
                    "sun",
                    reference_chart_start,
                    reference_sun_chart_end,
                    axis_seconds,
                ),
                await status_timeline_lane(
                    session,
                    "reference",
                    "Parkering",
                    reference_config["label"],
                    "parking",
                    reference_chart_start,
                    reference_parking_chart_end,
                    axis_seconds,
                ),
            ]
            reference_results.append(
                {
                    "config": reference_config,
                    "sun": reference_sun,
                    "parking": reference_parking,
                    "lanes": reference_lanes,
                }
            )

    current_summary = status_period_summary(
        current_config["label"],
        current_config["start"],
        current_config["sunEnd"],
        current_config["parkingEnd"],
        current_sun,
        current_parking,
        today,
    )
    comparison_summary = status_period_summary(
        comparison_config["label"],
        comparison_config["start"],
        comparison_config["sunEnd"],
        comparison_config["parkingEnd"],
        comparison_sun,
        comparison_parking,
        today,
    )
    reference_payloads = []
    for reference_result in reference_results:
        reference_config = reference_result["config"]
        reference_summary = status_period_summary(
            reference_config["label"],
            reference_config["start"],
            reference_config["sunEnd"],
            reference_config["parkingEnd"],
            reference_result["sun"],
            reference_result["parking"],
            today,
        )
        reference_payloads.append(
            {
                "key": reference_config["key"],
                "label": reference_config["label"],
                "summary": reference_summary,
                "delta": {
                    "sol": current_summary["sol"] - reference_summary["sol"],
                    "solCount": current_summary["solCount"] - reference_summary["solCount"],
                    "parking": current_summary["parking"] - reference_summary["parking"],
                    "parkingCount": current_summary["parkingCount"] - reference_summary["parkingCount"],
                    "total": current_summary["total"] - reference_summary["total"],
                },
                "lanes": reference_result["lanes"],
            }
        )
    axis_end = current_chart_start + timedelta(seconds=axis_seconds)
    return {
        "generatedAt": api_local_iso(now_dt),
        "periodKey": period,
        "comparisonKey": compare,
        "anchor": period_config["anchor"],
        "title": period_config["title"],
        "comparisonLabel": comparison_config["label"],
        "navigation": period_config["navigation"],
        "axis": {
            "start": api_local_iso(current_chart_start),
            "end": api_local_iso(axis_end),
            "seconds": axis_seconds,
            "ticks": status_timeline_ticks(current_chart_start, axis_seconds),
        },
        "current": current_summary,
        "comparison": comparison_summary,
        "delta": {
            "sol": current_summary["sol"] - comparison_summary["sol"],
            "solCount": current_summary["solCount"] - comparison_summary["solCount"],
            "parking": current_summary["parking"] - comparison_summary["parking"],
            "parkingCount": current_summary["parkingCount"] - comparison_summary["parkingCount"],
            "total": current_summary["total"] - comparison_summary["total"],
        },
        "lanes": lanes,
        "referenceComparisons": reference_payloads,
    }


@app.get("/api/soling/year-comparison")
async def api_v2_sun2_year_comparison(year: Optional[str] = Query(None)):
    now_dt = local_now_naive()
    today = now_dt.date()
    current_year = today.year
    anchor_year = parse_anchor_year(year, current_year)
    comparison_year = anchor_year - 1
    selected_as_of_day = today.timetuple().tm_yday if anchor_year == current_year else days_in_year(anchor_year)
    comparison_as_of_day = min(selected_as_of_day, days_in_year(comparison_year))
    selected_as_of_date = date(anchor_year, 1, 1) + timedelta(days=selected_as_of_day - 1)
    comparison_as_of_date = date(comparison_year, 1, 1) + timedelta(days=comparison_as_of_day - 1)

    async with async_session() as session:
        summaries = await get_sun2_summaries(session)

    daily_by_year = sun2_daily_by_year(summaries)
    selected_series = sun2_year_series(daily_by_year, anchor_year, selected_as_of_day, "current", "#f59e0b")
    comparison_series = sun2_year_series(daily_by_year, comparison_year, comparison_as_of_day, "comparison", "#64748b")
    comparison_full_series = sun2_year_series(
        daily_by_year,
        comparison_year,
        days_in_year(comparison_year),
        "comparison-full",
        "#94a3b8",
    )
    available_years = sorted(set(daily_by_year.keys()) | {anchor_year, comparison_year}, reverse=True)
    all_series = []
    for index, series_year in enumerate(available_years):
        series_as_of_day = today.timetuple().tm_yday if series_year == current_year else days_in_year(series_year)
        if series_year == anchor_year:
            source = "current"
        elif series_year == comparison_year:
            source = "comparison"
        else:
            source = "reference"
        all_series.append(
            sun2_year_series(
                daily_by_year,
                series_year,
                series_as_of_day,
                source,
                YEAR_COMPARISON_COLORS[index % len(YEAR_COMPARISON_COLORS)],
            )
        )
    axis_days = max([selected_series["daysInYear"], comparison_full_series["daysInYear"], *(item["daysInYear"] for item in all_series)])
    month_names = ["Jan", "Feb", "Mar", "Apr", "Mai", "Jun", "Jul", "Aug", "Sep", "Okt", "Nov", "Des"]
    ticks = []
    for month_index, month_name in enumerate(month_names, start=1):
        tick_date = date(anchor_year, month_index, 1)
        ticks.append({"label": month_name, "day": tick_date.timetuple().tm_yday})

    return {
        "generatedAt": api_local_iso(now_dt),
        "title": "Soling sammenligning",
        "anchorYear": anchor_year,
        "comparisonYear": comparison_year,
        "navigation": year_comparison_navigation(anchor_year, current_year),
        "axis": {"days": axis_days, "ticks": ticks},
        "availableYears": available_years,
        "series": all_series,
        "selected": selected_series,
        "comparison": comparison_series,
        "comparisonFull": comparison_full_series,
        "delta": sun2_year_comparison_delta(selected_series, comparison_series),
        "asOf": {
            "selectedLabel": "Hittil i år" if anchor_year == current_year else "Hele året",
            "selectedDate": selected_as_of_date.isoformat(),
            "comparisonLabel": "Til samme dag i året",
            "comparisonDate": comparison_as_of_date.isoformat(),
        },
    }


