        load.fibaro_device_id = form_int(form, "fibaro_device_id")
        load.fibaro_meter_id = form_int(form, "fibaro_meter_id")
        load.zwave_switch_id = form_int(form, "zwave_switch_id")
        load.controllable = form_bool(form, "controllable")
